    <script>
      {
      const root = document.currentScript.parentElement;
      const find = (sel) => root.querySelector(sel);

      let parsedGame = {};
      let statData = {};
      let displayData = {}; 
      let actionQueue = [];
      const settingsKey = 'garden-dashboard-settings';

      // ==========================================
      // 🌟 TỪ ĐIỂN UI THÔNG MINH (TỰ ĐỘNG DỊCH TỪ GHÉP) 🌟
      // ==========================================
     const uiDict = {
          // 1. Tên Nhân Vật & Nhân viên
          "阿芙洛狄忒": "Aphrodite", "伊丝卡": "Iska", "菲娜": "Fina", "莉安娜": "Liana",
          "克拉拉": "Clara", "杜拉罕": "Dullahan", "维多利亚": "Victoria", "奥萝拉": "Aurora",
          "安妮": "Annie", "斯莱姆": "Slime", "米娅": "Mia", "亚雷克": "Alec", "雪音": "Yukine",
          "芙蕾雅": "Freya", "蕾比": "Levy", "夏琉": "Natsuru", "伊莉亚": "Illya", "赛拉菲娜": "Seraphina",
          "双胞胎": "Song sinh (Ellie, Ella)", "伊芙琳": "Evelyn", "法琳娜": "Falina", "伊格妮斯": "Ignis",
          "卡特琳娜": "Katrina", "娜塔莉": "Natalie", "克拉丽斯": "Clarice", "佩西娅": "Persia",
          "哈基米": "Hakimi", "亚雷克·兰德": "Alec Rand",
          "夏琳": "Hạ Lâm", // <--- BẠN THÊM VÀO ĐÂY NHÉ

          // 2. Vật phẩm & Thành tựu cố định
          "无法离店": "Không thể rời cửa hàng",
          "系统平板": "Máy tính bảng hệ thống",
          "粉色小猪存钱罐": "Ống heo tiết kiệm màu hồng",
          "《精灵情爱图鉴》": "《Sách tranh tình ái Tinh linh》",
          "初出茅庐": "Mới vào nghề",
          "开业大吉": "Khai trương đại cát",
          "凯瑞恩": "Kaelen",
          "麦克": "Mike",

          // 3. Đồ chơi AI hay chế (Sửa dứt điểm ảnh 6)
          "源泉": "Suối nguồn",
          "荒野呼唤": "Tiếng gọi hoang dã",
          "绿巨人": "Hulk",
          "润滑液“源泉”": "Dầu bôi trơn 'Suối nguồn'",
          "跳蛋“荒野呼唤”": "Trứng rung 'Tiếng gọi hoang dã'",
          "假阳具“绿巨人”": "Dương vật giả 'Hulk'",

          // 4. Hàm Dịch Thuật Thông Minh (Xử lý đồ AI tự chế)
          get(key) { 
              if (!key) return key;
              if (this[key]) return this[key]; // Nếu có sẵn thì dịch luôn

              let k = key;
              // Danh sách các tiền tố đồ vật AI hay chế tên
              const prefixes = {
                  "润滑液": "Dầu bôi trơn ", "润滑油": "Dầu bôi trơn ",
                  "跳蛋": "Trứng rung ", "假阳具": "Dương vật giả ",
                  "按摩棒": "Gậy rung ", "情趣内衣": "Nội y tình thú ",
                  "避孕套": "Bao cao su ", "媚药": "Thuốc kích dục ",
                  "(普通型)": "(Cơ bản)", "(通用型)": "(Đa dụng)", "(有线版)": "(Có dây)"
              };

              // Tự động quét và dịch phần đầu của từ ghép
              for (let [zh, vi] of Object.entries(prefixes)) {
                  if (k.includes(zh)) k = k.replace(zh, vi);
              }

              // Sửa dấu ngoặc kép kiểu Trung Quốc thành kiểu thường
              k = k.replace(/“/g, '"').replace(/”/g, '"').replace(/（/g, ' (').replace(/）/g, ')');

              return k; 
          }
      };

      let purchasePreview = null; let purchasePreviewOld = null; 
      let productPreview = null; let productPreviewOld = null; 
      let removeProductPreview = null; let removeProductPreviewOld = null;

      // HÀM TÌM DỮ LIỆU USER THÔNG MINH (Chống lỗi đổi tên)
      function getHeroData(data) {
          if (!data) return {};
          if (data['当前月盈利'] !== undefined) return data; // Tìm thấy ngay ở root
          if (data['<user>']) return data['<user>'];
          if (data['']) return data[''];
          for (let key in data) {
              if (data[key] && typeof data[key] === 'object') {
                  if (data[key]['饱腹值'] !== undefined || data[key]['当前月盈利'] !== undefined || data[key]['精力值'] !== undefined) {
                      return data[key];
                  }
              }
          }
          return data; 
      }

      function findFirstElement(selectors) {
        for (const selector of selectors) { try { const el = window.parent?.document?.querySelector(selector); if (el) return el; } catch (err) { return null; } } return null;
      }
      function executeSillyTavernCommand(command) {
        const textareas = ['#send_textarea', '#main_textarea', 'textarea[name="message"]', '#input'], buttons = ['#send_but', '#send_button', 'button[type="submit"]', '#sendBtn', 'button.send-button'];
        const ta = findFirstElement(textareas), btn = findFirstElement(buttons);
        if (ta && btn) { ta.value = command; ta.dispatchEvent(new Event('input', { bubbles: true })); setTimeout(() => btn.click(), 80); return true; }
        try { window.parent.postMessage({ type: 'user_input', content: command }, '*'); return true; } catch (e) { return false; }
      }

      function getTagContent(raw, tag) {
        const nextTagLookahead = '<(?:context|briefing|user|people|products|achievements|purchase|actions|customers|clerks)';
        const regex = new RegExp(`<${tag}>([\\s\\S]*?)(?:<\\/|${nextTagLookahead}|$)`, 'i');
        const match = raw.match(regex); return match ? match[1].trim() : '';
      }
      function parseListSection(text) {
        if (!text) return [];
        return text.split('\n').map(l => l.trim()).filter(Boolean).map(line => {
            const parts = line.split('|').map(p => p.trim());
            return { name: parts[0] || '', appearance: parts[1] || '', action: parts[2] || '', thought: parts[3] || '' };
          });
      }
      function parsePurchaseSection(text) {
        if (!text) return [];
        return text.split('\n').map(l => l.trim()).filter(Boolean).map(line => {
            const parts = line.split('|').map(p => p.trim());
            return { name: parts[0] || '', price: Number(parts[1]) || 0, desc: parts[2] || '' };
          });
      }
      function parseActionsSection(text) { if (!text) return []; return text.split('|').map(i => i.trim()).filter(Boolean); }
      function parseBriefingSection(text) {
        if (!text) return { customerCount: 0, sales: [], profit: 0, losses: [], revenue: 0, comments: [] };
        const lines = text.split('\n').map(l => l.trim()).filter(Boolean);
        let customerCount = 0, sales = [], profit = 0, losses = [], revenue = 0, comments = [], situations = [];
        let inSales = false, inLosses = false, inComments = false, inSituations = false;
        lines.forEach(line => {
          if (line.startsWith('顾客数量:')) customerCount = parseInt(line.replace('顾客数量:', '').trim()) || 0;
          else if (line.startsWith('销售商品:')) { inSales = true; inLosses = false; inComments = false; inSituations = false; }
          else if (line.startsWith('损耗商品:')) { inLosses = true; inSales = false; inComments = false; inSituations = false; }
          else if (line.startsWith('销售额:')) { revenue = parseInt(line.replace('销售额:', '').trim()) || 0; inSales = false; inLosses = false; inComments = false; inSituations = false; }
          else if (line.startsWith('盈利:')) { profit = parseInt(line.replace('盈利:', '').trim()) || 0; inSales = false; inLosses = false; inComments = false; inSituations = false; }
          else if (line.startsWith('店内情况:')) { inSituations = true; inSales = false; inLosses = false; inComments = false; }
          else if (line.startsWith('点评:')) { inComments = true; inSales = false; inLosses = false; inSituations = false; }
          else if (inSales && line.includes('|')) { const parts = line.split('|').map(p => p.trim()); if (parts.length >= 2 && parts[0] !== '无') sales.push({ name: parts[0], quantity: parseInt(parts[1]) || 0 }); }
          else if (inLosses && line.includes('|')) { const parts = line.split('|').map(p => p.trim()); if (parts.length >= 2 && parts[0] !== '无') losses.push({ name: parts[0], quantity: parseInt(parts[1]) || 0 }); }
          else if (inSituations && line.trim() && line !== '无') situations.push(line.trim());
          else if (inComments && line.trim() && line !== '无') comments.push(line.trim());
        });
        return { customerCount, sales, profit, losses, revenue, comments, situations };
      }
      function parseGameText() {
        const raw = find('.gametext')?.innerHTML || '';
        const context = getTagContent(raw, 'context').replace(/<br\s*\/?>/gi, '\n');
        const customers = parseListSection(getTagContent(raw, 'customers'));
        const clerks = parseListSection(getTagContent(raw, 'clerks'));
        const purchase = parsePurchaseSection(getTagContent(raw, 'purchase'));
        const actions = parseActionsSection(getTagContent(raw, 'actionslog'));
        const briefing = parseBriefingSection(getTagContent(raw, 'briefing'));
        const activeCharsRaw = getTagContent(raw, 'stat');
        const activeCharacters = activeCharsRaw ? activeCharsRaw.split('|').map(s => s.trim()).filter(Boolean) : [];
        return { context, customers, clerks, purchase, actions, briefing, activeCharacters };
      }

      function parseStatData() {
        const raw = find('.stat-data')?.textContent || ''; if (!raw || !raw.trim()) return {};
        let cleaned = raw.replace(/\r\n/g, ' ').replace(/\n/g, ' ').replace(/\r/g, ' ').replace(/\s+/g, ' ').trim();
        cleaned = cleaned.replace(/&quot;/g, '"');
        try { return JSON.parse(cleaned); } catch (err) { return {}; }
      }

      function parseDisplayData() {
        const raw = find('.display-data')?.textContent || ''; if (!raw || !raw.trim()) return {};
        let cleaned = raw.replace(/\r\n/g, ' ').replace(/\n/g, ' ').trim();
        try { return JSON.parse(cleaned); } catch (err) { return {}; }
      }

      function analyzeDisplayValue(val) {
        if (typeof val !== 'string' || !val.includes('->')) return { isChange: false, displayVal: val };
        try {
            const parts = val.split('->'), oldValStr = parts[0].trim().replace(/,/g, ''), rightPart = parts[1].trim();
            const parenIndex = rightPart.indexOf('(');
            let candidateValStr = rightPart, reason = '', hasReason = false;
             if (parenIndex !== -1) {
                candidateValStr = rightPart.substring(0, parenIndex).trim(); const endParenIndex = rightPart.lastIndexOf(')');
                reason = rightPart.substring(parenIndex + 1, endParenIndex !== -1 ? endParenIndex : rightPart.length).trim(); hasReason = true;
             }
            if (/^[-\d,.]+$/.test(candidateValStr)) {
                const newNum = parseFloat(candidateValStr.replace(/,/g, '')), oldNum = parseFloat(oldValStr);
                if (!isNaN(oldNum) && !isNaN(newNum)) {
                    const diff = newNum - oldNum, sign = diff > 0 ? '+' : '', diffDisplay = Number.isInteger(diff) ? diff : diff.toFixed(1);
                    return { isChange: true, displayVal: newNum, diffStr: `${sign}${diffDisplay}`, reason: hasReason ? reason : 'Cập nhật số liệu', tooltipRaw: hasReason ? `<strong>Thay đổi: ${sign}${diffDisplay}</strong><br>${reason}` : `<strong>Thay đổi: ${sign}${diffDisplay}</strong>` };
                }
            }
            return { isChange: true, displayVal: rightPart, diffStr: 'Cập nhật', reason: '', tooltipRaw: `<strong>Cập nhật nội dung</strong>` };
        } catch (e) { return { isChange: false, displayVal: val }; }
      }

      function parseAssignedString(str) {
        if (typeof str !== 'string' || !str.startsWith('ASSIGNED')) return null;
        const arrayMatch = str.match(/ASSIGNED\s+"(.*?)"\s+into\s+array/); if (arrayMatch) return { type: 'array', content: arrayMatch[1] };
        const keyMatch = str.match(/ASSIGNED\s+key\s+'(.*?)'\s+with/); if (keyMatch) return { type: 'key', key: keyMatch[1] };
        return null;
      }

      function renderContext() {
        const el = document.getElementById('context-body'); let context = parsedGame.context || 'Tạm thời không có nội dung';
        context = context.replace(/<\/?user>/gi, '').trim(); el.textContent = context;
      }
      function renderTime() {
        const rawDate = statData['日期'], rawTime = statData['时间'];
        document.getElementById('status-date').textContent = Array.isArray(rawDate) ? rawDate[0] : (rawDate || 'Ngày chưa rõ');
        document.getElementById('status-time').textContent = Array.isArray(rawTime) ? rawTime[0] : (rawTime || 'Thời gian chưa rõ');
      }

      // ==========================================
      // FIX LỖI THANH % BỊ MẤT KHI LỢI NHUẬN = 0
      // ==========================================
    function renderStatus() {
        let userData = getHeroData(statData);
        const currentProfit = userData['当前月盈利'] || 0;
        const targetProfit = userData['目标月盈利'] || statData['目标月盈利'] || 10000;

        updateFundsDisplay();
        document.getElementById('status-profit').textContent = currentProfit.toLocaleString();
        document.getElementById('status-target').textContent = targetProfit.toLocaleString();

        let progressPercent = targetProfit > 0 ? (currentProfit / targetProfit) * 100 : 0;
        progressPercent = Math.min(100, Math.max(0, progressPercent)); 

        const progressBar = document.getElementById('profit-progress');
        if (progressBar) {
          if (currentProfit === 0) {
             // Khi chưa có lợi nhuận, tàng hình thanh xanh
             progressBar.style.width = '100%';
             progressBar.style.background = 'transparent';
             progressBar.style.color = 'var(--muted-text-color)';
             progressBar.style.justifyContent = 'flex-start';
             progressBar.style.paddingLeft = '10px';
             progressBar.textContent = '0%';
          } else {
             // Khi có lợi nhuận, tính toán chi tiết
             // Nếu >= 1% thì làm tròn, nếu < 1% thì hiện 2 số thập phân (VD: 0.35%)
             let displayPercent = progressPercent >= 1 ? Math.round(progressPercent) : progressPercent.toFixed(2);

             // Giữ độ dài thanh tối thiểu là 6% để chữ không bị tràn ra ngoài
             let visualWidth = progressPercent < 6 ? 6 : progressPercent;

             progressBar.style.width = `${visualWidth}%`;
             progressBar.style.background = 'linear-gradient(90deg, var(--primary-color), var(--secondary-color))';
             progressBar.style.color = 'var(--success-text)';
             progressBar.style.justifyContent = 'center';
             progressBar.style.paddingLeft = '0';
             progressBar.textContent = `${displayPercent}%`;
          }
        }
      }

   function renderUserInfo() {
        const container = document.getElementById('user-info-content'); if (!container) return;

        let userData = getHeroData(statData);
        let userChange = getHeroData(displayData);

        const primaryFields = [
          { key: '资金', label: 'Tiền', icon: 'fa-coins', color: 'var(--accent-gold)' }, { key: '当前月盈利', label: 'Lợi nhuận tháng', icon: 'fa-chart-line', color: 'var(--success-text)' },
          { key: '目标月盈利', label: 'Mục tiêu tháng', icon: 'fa-bullseye', color: 'var(--text-color)' }, { key: '店铺知名度', label: 'Độ nổi tiếng', icon: 'fa-star', color: 'var(--accent-yellow)' },
        ];
        const barFields = [{ key: '饱腹值', label: 'Độ no' }, { key: '精力值', label: 'Tinh lực' }, { key: '生命值', label: 'Máu HP' }];

        let html = '<div style="display:flex; flex-direction:column; gap:16px;">';
        const renderDeltaVal = (baseVal, changeVal) => {
             const rawVal = changeVal !== undefined ? changeVal : baseVal, analysis = analyzeDisplayValue(rawVal);
             let valDisplay = analysis.displayVal;
